240	}) {
241	  const binding = normalizeTelegramAcpConversationId(params.bindingConversationId);
242	  if (!binding) {
243	    return null;
244	  }
245	  const incoming = parseTelegramTopicConversation({
246	    conversationId: params.conversationId,
247	    parentConversationId: params.parentConversationId,
248	  });
249	  if (!incoming || !incoming.chatId.startsWith("-")) {
250	    return null;
251	  }
252	  if (binding.conversationId !== incoming.canonicalConversationId) {
253	    return null;
254	  }
255	  return {
256	    conversationId: incoming.canonicalConversationId,
257	    parentConversationId: incoming.chatId,
