358	type ChatChannelSecurityOptions<TResolvedAccount extends { accountId?: string | null }> = {
359	  dm: {
360	    channelKey: string;
361	    resolvePolicy: (account: TResolvedAccount) => string | null | undefined;
362	    resolveAllowFrom: (account: TResolvedAccount) => Array<string | number> | null | undefined;
363	    resolveFallbackAccountId?: (account: TResolvedAccount) => string | null | undefined;
364	    defaultPolicy?: string;
365	    allowFromPathSuffix?: string;
366	    policyPathSuffix?: string;
367	    approveChannelId?: string;
368	    approveHint?: string;
369	    normalizeEntry?: (raw: string) => string;
370	  };
371	  collectWarnings?: ChannelSecurityAdapter<TResolvedAccount>["collectWarnings"];
372	};
