374	type ChatChannelPairingOptions = {
375	  text: {
376	    idLabel: string;
377	    message: string;
378	    normalizeAllowEntry?: ChannelPairingAdapter["normalizeAllowEntry"];
379	    notify: (
380	      params: Parameters<NonNullable<ChannelPairingAdapter["notifyApproval"]>>[0] & {
381	        message: string;
382	      },
383	    ) => Promise<void> | void;
384	  };
385	};
